const fs = require('fs');
const path = require('path');
const _ = require('lodash');

/**
 *
 */
class AddEntryPlugin{

    constructor({
        entry = null
    } = {}){
        this.entry = _.isArray(entry) ? entry : [entry];
    }
    apply(compiler){

        compiler.plugin('compilation', compilation => {

            compilation.plugin('additional-assets', callback => {

                _.forEach(this.entry, v => {

                    const baseName = path.basename(v);

                    const stat = fs.statSync(v);
                    const content = fs.readFileSync(v, 'utf-8');

                    compilation.fileDependencies.push(v);

                    compilation.assets[baseName] = {
                        size: () => {
                            return stat.size;
                        },
                        source: () => {
                            return content;
                        }
                    };
                });

                callback();
            });
        });
    }
}

module.exports = AddEntryPlugin;

  
